import{_ as i,o as a,c as l,ag as t}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"QiLedger Blueprint","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/40_service_apps/40_productivity/qiledger.md","filePath":"10_core/40_service_apps/40_productivity/qiledger.md"}'),o={name:"10_core/40_service_apps/40_productivity/qiledger.md"};function r(n,e,s,c,d,u){return a(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="qiledger-blueprint" tabindex="-1">QiLedger Blueprint <a class="header-anchor" href="#qiledger-blueprint" aria-label="Permalink to &quot;QiLedger Blueprint&quot;">тАЛ</a></h1><h2 id="_1-project-name" tabindex="-1">1. Project Name <a class="header-anchor" href="#_1-project-name" aria-label="Permalink to &quot;1. Project Name&quot;">тАЛ</a></h2><p><strong>QiLedger</strong> Working title: <strong>FinanceOS Ledger</strong></p><p>A custom web-based money activity system for tracking, reviewing, categorizing, and reporting all financial activity across personal, household, business, legal, and caregiver-related money flows.</p><hr><h1 id="_2-core-goal" tabindex="-1">2. Core Goal <a class="header-anchor" href="#_2-core-goal" aria-label="Permalink to &quot;2. Core Goal&quot;">тАЛ</a></h1><p>Build a centralized, web-based general ledger that captures <strong>all money activity</strong> across accounts and contexts, then turns that activity into clear, filterable, reportable records.</p><p>The system should answer:</p><blockquote><p>Who was money for? What was it spent on? When did it happen? Where did it come from? Which account touched it? Was it personal, household, business, legal, caregiver, or tax-related? Has it been reviewed? Can it support a report, reimbursement, tax record, legal record, or budget decision?</p></blockquote><hr><h1 id="_3-problem-statement" tabindex="-1">3. Problem Statement <a class="header-anchor" href="#_3-problem-statement" aria-label="Permalink to &quot;3. Problem Statement&quot;">тАЛ</a></h1><p>Existing finance tools do not fit the actual use case.</p><h2 id="current-tool-issues" tabindex="-1">Current tool issues <a class="header-anchor" href="#current-tool-issues" aria-label="Permalink to &quot;Current tool issues&quot;">тАЛ</a></h2><h3 id="money-manager-ex" tabindex="-1">Money Manager Ex <a class="header-anchor" href="#money-manager-ex" aria-label="Permalink to &quot;Money Manager Ex&quot;">тАЛ</a></h3><p>Good local ledger, but:</p><ul><li>not web-based</li><li>difficult to access across devices</li><li>limited automation</li><li>not ideal for household/business/legal blended reporting</li><li>not built around modern API workflows</li></ul><h3 id="google-sheets-excel" tabindex="-1">Google Sheets / Excel <a class="header-anchor" href="#google-sheets-excel" aria-label="Permalink to &quot;Google Sheets / Excel&quot;">тАЛ</a></h3><p>Flexible, but:</p><ul><li>messy over time</li><li>weak relational structure</li><li>poor audit trail</li><li>hard to normalize vendors/categories/accounts</li><li>not ideal for long-term automation</li></ul><h3 id="quickbooks" tabindex="-1">QuickBooks <a class="header-anchor" href="#quickbooks" aria-label="Permalink to &quot;QuickBooks&quot;">тАЛ</a></h3><p>Rejected.</p><p>Reasons:</p><ul><li>too rigid</li><li>too expensive</li><li>too accountant-centric</li><li>overbuilt for this blended personal/household/business/legal use case</li><li>painful UI</li><li>bad fit for fast personal operations</li></ul><h3 id="zoho-books-quicken-other-apps" tabindex="-1">Zoho Books / Quicken / Other Apps <a class="header-anchor" href="#zoho-books-quicken-other-apps" aria-label="Permalink to &quot;Zoho Books / Quicken / Other Apps&quot;">тАЛ</a></h3><p>Problems:</p><ul><li>freemium limits</li><li>subscription traps</li><li>too consumer-focused or too enterprise-focused</li><li>weak custom reporting</li><li>not designed around caregiver/household/legal/business overlap</li></ul><hr><h1 id="_4-strategic-diagnosis" tabindex="-1">4. Strategic Diagnosis <a class="header-anchor" href="#_4-strategic-diagnosis" aria-label="Permalink to &quot;4. Strategic Diagnosis&quot;">тАЛ</a></h1><p>This project sits between categories:</p><h2 id="not-just-personal-budgeting" tabindex="-1">Not just personal budgeting <a class="header-anchor" href="#not-just-personal-budgeting" aria-label="Permalink to &quot;Not just personal budgeting&quot;">тАЛ</a></h2><p>Because the system must handle:</p><ul><li>household contributions</li><li>caregiver-related spending</li><li>shared bills</li><li>reimbursable items</li><li>account transfers</li><li>legal case expenses</li><li>business expenses</li><li>tax support</li><li>recurring bills</li><li>receipts and statements</li><li>multiple people/entities</li></ul><h2 id="not-full-business-accounting" tabindex="-1">Not full business accounting <a class="header-anchor" href="#not-full-business-accounting" aria-label="Permalink to &quot;Not full business accounting&quot;">тАЛ</a></h2><p>Because the goal is not traditional bookkeeping first.</p><p>The goal is:</p><blockquote><p>Money intelligence first, formal accounting second.</p></blockquote><h2 id="not-enterprise-finance-ops" tabindex="-1">Not enterprise finance ops <a class="header-anchor" href="#not-enterprise-finance-ops" aria-label="Permalink to &quot;Not enterprise finance ops&quot;">тАЛ</a></h2><p>Because it must remain lightweight, fast, and usable by one person under real-life pressure.</p><hr><h1 id="_5-product-philosophy" tabindex="-1">5. Product Philosophy <a class="header-anchor" href="#_5-product-philosophy" aria-label="Permalink to &quot;5. Product Philosophy&quot;">тАЛ</a></h1><p>QiLedger is not trying to replace full accounting software immediately.</p><p>It is a <strong>ledger intelligence layer</strong>.</p><p>The system should prioritize:</p><ol><li>Fast capture</li><li>Clean review</li><li>Unified transaction history</li><li>Easy categorization</li><li>Relationship tracking</li><li>Reporting by context</li><li>Audit support</li><li>Exportability</li><li>Automation readiness</li></ol><p>The system should avoid:</p><ul><li>overbuilding</li><li>full double-entry accounting in v1</li><li>complex invoicing</li><li>payroll</li><li>tax filing</li><li>bloated dashboards</li><li>enterprise permissions</li><li>unnecessary accounting jargon</li><li>trying to become QuickBooks</li></ul><hr><h1 id="_6-core-doctrine" tabindex="-1">6. Core Doctrine <a class="header-anchor" href="#_6-core-doctrine" aria-label="Permalink to &quot;6. Core Doctrine&quot;">тАЛ</a></h1><h2 id="doctrine-1-postgres-is-the-source-of-truth" tabindex="-1">Doctrine 1: Postgres is the source of truth <a class="header-anchor" href="#doctrine-1-postgres-is-the-source-of-truth" aria-label="Permalink to &quot;Doctrine 1: Postgres is the source of truth&quot;">тАЛ</a></h2><p>The database is the real system.</p><p>The UI is replaceable.</p><p>No app builder, no-code platform, spreadsheet, or dashboard tool should become the foundation.</p><h2 id="doctrine-2-every-money-event-becomes-a-normalized-record" tabindex="-1">Doctrine 2: Every money event becomes a normalized record <a class="header-anchor" href="#doctrine-2-every-money-event-becomes-a-normalized-record" aria-label="Permalink to &quot;Doctrine 2: Every money event becomes a normalized record&quot;">тАЛ</a></h2><p>Raw bank data can be messy.</p><p>The system must normalize it into consistent transaction records.</p><h2 id="doctrine-3-imported-data-and-reviewed-data-are-separate" tabindex="-1">Doctrine 3: Imported data and reviewed data are separate <a class="header-anchor" href="#doctrine-3-imported-data-and-reviewed-data-are-separate" aria-label="Permalink to &quot;Doctrine 3: Imported data and reviewed data are separate&quot;">тАЛ</a></h2><p>Never destroy the original import.</p><p>Use a staging/inbox model:</p><p><strong>Raw import тЖТ reviewed transaction тЖТ unified ledger</strong></p><h2 id="doctrine-4-reports-are-views-not-separate-spreadsheets" tabindex="-1">Doctrine 4: Reports are views, not separate spreadsheets <a class="header-anchor" href="#doctrine-4-reports-are-views-not-separate-spreadsheets" aria-label="Permalink to &quot;Doctrine 4: Reports are views, not separate spreadsheets&quot;">тАЛ</a></h2><p>Once the ledger is clean, reports should come from filters and views.</p><p>Do not manually rebuild reports in separate files unless exporting for outside use.</p><h2 id="doctrine-5-build-for-real-life-not-perfect-accounting-theory" tabindex="-1">Doctrine 5: Build for real life, not perfect accounting theory <a class="header-anchor" href="#doctrine-5-build-for-real-life-not-perfect-accounting-theory" aria-label="Permalink to &quot;Doctrine 5: Build for real life, not perfect accounting theory&quot;">тАЛ</a></h2><p>The first priority is operational clarity.</p><p>Formal accounting can be layered in later.</p><hr><h1 id="_7-system-overview" tabindex="-1">7. System Overview <a class="header-anchor" href="#_7-system-overview" aria-label="Permalink to &quot;7. System Overview&quot;">тАЛ</a></h1><h2 id="high-level-flow" tabindex="-1">High-Level Flow <a class="header-anchor" href="#high-level-flow" aria-label="Permalink to &quot;High-Level Flow&quot;">тАЛ</a></h2><ol><li>User imports or enters money activity.</li><li>Activity lands in a review inbox.</li><li>System normalizes vendor, category, account, person, project, and context.</li><li>User reviews and approves transaction.</li><li>Approved transaction becomes part of the unified ledger.</li><li>Reports and dashboards pull from the unified ledger.</li><li>Rules improve future categorization.</li></ol><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">тАЛ</a></h2><p><strong>Bank / Card / Cash / Manual Entry</strong> тЖТ <strong>Import Batch</strong> тЖТ <strong>Raw Transactions</strong> тЖТ <strong>Money Inbox</strong> тЖТ <strong>Reviewed Ledger Transactions</strong> тЖТ <strong>Reports / Views / Exports</strong></p><hr><h1 id="_8-main-user-experience" tabindex="-1">8. Main User Experience <a class="header-anchor" href="#_8-main-user-experience" aria-label="Permalink to &quot;8. Main User Experience&quot;">тАЛ</a></h1><p>The daily experience should be fast.</p><p>The user should not feel like they are тАЬdoing accounting.тАЭ</p><p>They should feel like they are clearing an inbox.</p><h2 id="primary-workflow" tabindex="-1">Primary workflow <a class="header-anchor" href="#primary-workflow" aria-label="Permalink to &quot;Primary workflow&quot;">тАЛ</a></h2><ol><li>Open QiLedger.</li><li>See unreviewed transactions.</li><li>Approve obvious items.</li><li>Fix unclear items.</li><li>Assign category/person/project.</li><li>Mark transfers.</li><li>Add notes or receipts where needed.</li><li>View reports when needed.</li></ol><hr><h1 id="_9-core-screens" tabindex="-1">9. Core Screens <a class="header-anchor" href="#_9-core-screens" aria-label="Permalink to &quot;9. Core Screens&quot;">тАЛ</a></h1><h2 id="_9-1-money-inbox" tabindex="-1">9.1 Money Inbox <a class="header-anchor" href="#_9-1-money-inbox" aria-label="Permalink to &quot;9.1 Money Inbox&quot;">тАЛ</a></h2><p>The most important screen.</p><p>Purpose:</p><blockquote><p>Show transactions that need review.</p></blockquote><h3 id="key-features" tabindex="-1">Key features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key features&quot;">тАЛ</a></h3><ul><li>list of unreviewed transactions</li><li>quick approve button</li><li>category dropdown</li><li>person dropdown</li><li>project/context dropdown</li><li>vendor normalization</li><li>transfer matching</li><li>split transaction option</li><li>notes field</li><li>receipt attachment</li><li>confidence indicator</li><li>rule suggestion</li></ul><h3 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">тАЛ</a></h3><ul><li>account</li><li>date range</li><li>amount range</li><li>vendor</li><li>imported batch</li><li>possible transfer</li><li>needs category</li><li>needs person</li><li>needs project</li><li>low confidence</li></ul><hr><h2 id="_9-2-unified-ledger" tabindex="-1">9.2 Unified Ledger <a class="header-anchor" href="#_9-2-unified-ledger" aria-label="Permalink to &quot;9.2 Unified Ledger&quot;">тАЛ</a></h2><p>The master transaction view.</p><p>Purpose:</p><blockquote><p>Show all reviewed money activity in one normalized table.</p></blockquote><h3 id="must-support-filtering-by" tabindex="-1">Must support filtering by <a class="header-anchor" href="#must-support-filtering-by" aria-label="Permalink to &quot;Must support filtering by&quot;">тАЛ</a></h3><ul><li>date</li><li>account</li><li>person</li><li>category</li><li>vendor</li><li>project</li><li>context</li><li>amount</li><li>direction</li><li>reviewed status</li><li>tax relevance</li><li>legal relevance</li><li>household relevance</li><li>business relevance</li></ul><h3 id="transaction-fields-displayed" tabindex="-1">Transaction fields displayed <a class="header-anchor" href="#transaction-fields-displayed" aria-label="Permalink to &quot;Transaction fields displayed&quot;">тАЛ</a></h3><ul><li>transaction date</li><li>account</li><li>vendor/payee</li><li>description</li><li>amount</li><li>direction</li><li>category</li><li>person</li><li>project</li><li>context</li><li>reviewed status</li><li>notes</li></ul><hr><h2 id="_9-3-accounts" tabindex="-1">9.3 Accounts <a class="header-anchor" href="#_9-3-accounts" aria-label="Permalink to &quot;9.3 Accounts&quot;">тАЛ</a></h2><p>Tracks every place money can exist or move through.</p><p>Examples:</p><ul><li>Chase Checking</li><li>Cash App</li><li>PayPal</li><li>Venmo</li><li>Mom Clearing</li><li>Zai Clearing</li><li>Household Bills</li><li>Business Income</li><li>Legal Costs</li><li>Cash on Hand</li><li>Credit Card</li><li>Prepaid Card</li></ul><h3 id="account-types" tabindex="-1">Account types <a class="header-anchor" href="#account-types" aria-label="Permalink to &quot;Account types&quot;">тАЛ</a></h3><ul><li>checking</li><li>savings</li><li>credit card</li><li>cash</li><li>digital wallet</li><li>clearing account</li><li>loan</li><li>liability</li><li>income source</li><li>external account</li></ul><hr><h2 id="_9-4-categories" tabindex="-1">9.4 Categories <a class="header-anchor" href="#_9-4-categories" aria-label="Permalink to &quot;9.4 Categories&quot;">тАЛ</a></h2><p>The chart of accounts / reporting categories.</p><p>This does not need to be overly formal in v1.</p><p>Examples:</p><ul><li>Income</li><li>Household Bills</li><li>Groceries</li><li>Medical</li><li>Transportation</li><li>Legal</li><li>Business Expense</li><li>Caregiver Expense</li><li>Debt Payment</li><li>Transfer</li><li>Reimbursement</li><li>Personal</li><li>Emergency</li><li>Subscriptions</li><li>Taxes</li></ul><hr><h2 id="_9-5-vendors-payees" tabindex="-1">9.5 Vendors / Payees <a class="header-anchor" href="#_9-5-vendors-payees" aria-label="Permalink to &quot;9.5 Vendors / Payees&quot;">тАЛ</a></h2><p>Normalizes messy bank descriptions.</p><p>Examples:</p><p>Raw:</p><ul><li><code>WM SUPERCENTER #1341</code></li><li><code>WALMART.COM 8009666546</code></li><li><code>WAL-MART STORE</code></li></ul><p>Normalized:</p><ul><li>Walmart</li></ul><p>Raw:</p><ul><li><code>ASTOUND BROADBAND</code></li><li><code>WOW INTERNET</code></li><li><code>RCN ASTOUND</code></li></ul><p>Normalized:</p><ul><li>Astound Internet</li></ul><hr><h2 id="_9-6-people-entities" tabindex="-1">9.6 People / Entities <a class="header-anchor" href="#_9-6-people-entities" aria-label="Permalink to &quot;9.6 People / Entities&quot;">тАЛ</a></h2><p>Tracks who the transaction relates to.</p><p>Examples:</p><ul><li>Cody</li><li>Mom</li><li>Zai</li><li>Household</li><li>Client</li><li>Court</li><li>Vendor</li><li>Business</li><li>Legal Case</li><li>Unknown</li></ul><p>This is critical because normal apps do not understand blended household operations.</p><hr><h2 id="_9-7-projects-contexts" tabindex="-1">9.7 Projects / Contexts <a class="header-anchor" href="#_9-7-projects-contexts" aria-label="Permalink to &quot;9.7 Projects / Contexts&quot;">тАЛ</a></h2><p>Tracks why the money matters.</p><p>Examples:</p><ul><li>Household Operations</li><li>Caregiver Support</li><li>Legal Case</li><li>Business Operations</li><li>Tax Prep</li><li>Vehicle Repair</li><li>Mom Medical Support</li><li>Home Repair</li><li>QiLabs</li><li>Personal Spending</li><li>Emergency Reset</li></ul><hr><h2 id="_9-8-reports" tabindex="-1">9.8 Reports <a class="header-anchor" href="#_9-8-reports" aria-label="Permalink to &quot;9.8 Reports&quot;">тАЛ</a></h2><p>MVP reports should be simple and useful.</p><h3 id="required-reports" tabindex="-1">Required reports <a class="header-anchor" href="#required-reports" aria-label="Permalink to &quot;Required reports&quot;">тАЛ</a></h3><ol><li><p>Cashflow report Money in vs money out.</p></li><li><p>Spending by category Where money went.</p></li><li><p>Spending by person/entity Who money was for.</p></li><li><p>Spending by account Which accounts were used.</p></li><li><p>Vendor report Who got paid.</p></li><li><p>Household report Shared household expenses.</p></li><li><p>Mom contribution report Contributions, expenses, balance, and usage.</p></li><li><p>Legal expense report Court, filing, document, transport, case-related costs.</p></li><li><p>Business expense report Tax/business-related expenses.</p></li><li><p>Uncategorized report Items needing cleanup.</p></li><li><p>Transfer report Movement between accounts.</p></li><li><p>Reimbursement report Items paid by one person/context that belong to another.</p></li></ol><hr><h1 id="_10-mvp-scope" tabindex="-1">10. MVP Scope <a class="header-anchor" href="#_10-mvp-scope" aria-label="Permalink to &quot;10. MVP Scope&quot;">тАЛ</a></h1><h2 id="mvp-must-include" tabindex="-1">MVP must include <a class="header-anchor" href="#mvp-must-include" aria-label="Permalink to &quot;MVP must include&quot;">тАЛ</a></h2><ul><li>web-based login</li><li>accounts table</li><li>categories table</li><li>vendors table</li><li>people/entities table</li><li>projects/contexts table</li><li>manual transaction entry</li><li>CSV import</li><li>raw transaction staging</li><li>money inbox review screen</li><li>unified ledger screen</li><li>basic reports</li><li>export to CSV</li><li>mobile-friendly layout</li></ul><h2 id="mvp-should-not-include-yet" tabindex="-1">MVP should not include yet <a class="header-anchor" href="#mvp-should-not-include-yet" aria-label="Permalink to &quot;MVP should not include yet&quot;">тАЛ</a></h2><ul><li>full double-entry accounting</li><li>bank API integrations</li><li>automatic Plaid sync</li><li>invoice generation</li><li>payroll</li><li>inventory</li><li>full tax filing</li><li>OCR receipt processing</li><li>AI categorization</li><li>advanced permissions</li><li>complex dashboards</li></ul><p>Those come later.</p><p>Do not let v1 become a productivity swamp.</p><hr><h1 id="_11-recommended-tech-stack" tabindex="-1">11. Recommended Tech Stack <a class="header-anchor" href="#_11-recommended-tech-stack" aria-label="Permalink to &quot;11. Recommended Tech Stack&quot;">тАЛ</a></h1><h2 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">тАЛ</a></h2><p><strong>React + TypeScript + Vite</strong></p><p>Reason:</p><ul><li>fast</li><li>familiar</li><li>flexible</li><li>works well with Supabase</li><li>easy to make mobile-first</li><li>supports future PWA use</li></ul><h2 id="backend-database" tabindex="-1">Backend / Database <a class="header-anchor" href="#backend-database" aria-label="Permalink to &quot;Backend / Database&quot;">тАЛ</a></h2><p><strong>Supabase Postgres</strong></p><p>Reason:</p><ul><li>hosted Postgres</li><li>auth included</li><li>row-level security available</li><li>APIs generated automatically</li><li>can export/migrate</li><li>works well with custom React apps</li></ul><h2 id="auth" tabindex="-1">Auth <a class="header-anchor" href="#auth" aria-label="Permalink to &quot;Auth&quot;">тАЛ</a></h2><p><strong>Supabase Auth</strong></p><p>MVP:</p><ul><li>single-user first</li><li>later add household/support users if needed</li></ul><h2 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">тАЛ</a></h2><p><strong>Supabase Storage or Google Drive link references</strong></p><p>For:</p><ul><li>statement files</li><li>receipts</li><li>exported reports</li><li>supporting documents</li></ul><p>MVP can store file metadata first, then add actual upload later.</p><h2 id="automation-layer" tabindex="-1">Automation Layer <a class="header-anchor" href="#automation-layer" aria-label="Permalink to &quot;Automation Layer&quot;">тАЛ</a></h2><p>Later:</p><ul><li>n8n</li><li>Python import scripts</li><li>AI categorization worker</li><li>statement parser</li><li>Drive sync</li></ul><hr><h1 id="_12-architecture" tabindex="-1">12. Architecture <a class="header-anchor" href="#_12-architecture" aria-label="Permalink to &quot;12. Architecture&quot;">тАЛ</a></h1><h2 id="core-architecture" tabindex="-1">Core architecture <a class="header-anchor" href="#core-architecture" aria-label="Permalink to &quot;Core architecture&quot;">тАЛ</a></h2><p><strong>Frontend Web App</strong> тЖТ Supabase client тЖТ Postgres tables тЖТ Views / RPC functions тЖТ Reports</p><h2 id="optional-later-architecture" tabindex="-1">Optional later architecture <a class="header-anchor" href="#optional-later-architecture" aria-label="Permalink to &quot;Optional later architecture&quot;">тАЛ</a></h2><p><strong>Statement Upload</strong> тЖТ Storage тЖТ Parser Worker тЖТ Raw Transactions тЖТ Rules Engine тЖТ Review Inbox тЖТ Unified Ledger</p><h2 id="principle" tabindex="-1">Principle <a class="header-anchor" href="#principle" aria-label="Permalink to &quot;Principle&quot;">тАЛ</a></h2><p>The frontend should not contain the financial logic.</p><p>The database should enforce:</p><ul><li>required fields</li><li>account relationships</li><li>category relationships</li><li>transaction integrity</li><li>duplicate prevention</li><li>review state</li></ul><hr><h1 id="_13-core-data-model" tabindex="-1">13. Core Data Model <a class="header-anchor" href="#_13-core-data-model" aria-label="Permalink to &quot;13. Core Data Model&quot;">тАЛ</a></h1><h2 id="_13-1-accounts" tabindex="-1">13.1 <code>accounts</code> <a class="header-anchor" href="#_13-1-accounts" aria-label="Permalink to &quot;13.1 `accounts`&quot;">тАЛ</a></h2><p>Stores financial accounts and clearing accounts.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>name</code></li><li><code>institution</code></li><li><code>account_type</code></li><li><code>owner_entity_id</code></li><li><code>last_four</code></li><li><code>currency</code></li><li><code>is_active</code></li><li><code>opening_balance</code></li><li><code>notes</code></li><li><code>created_at</code></li><li><code>updated_at</code></li></ul><hr><h2 id="_13-2-entities" tabindex="-1">13.2 <code>entities</code> <a class="header-anchor" href="#_13-2-entities" aria-label="Permalink to &quot;13.2 `entities`&quot;">тАЛ</a></h2><p>People, household members, businesses, vendors, institutions, courts, etc.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>name</code></li><li><code>entity_type</code></li><li><code>default_context</code></li><li><code>notes</code></li><li><code>created_at</code></li><li><code>updated_at</code></li></ul><p>Entity types:</p><ul><li>person</li><li>household</li><li>business</li><li>vendor</li><li>institution</li><li>court</li><li>client</li><li>other</li></ul><hr><h2 id="_13-3-categories" tabindex="-1">13.3 <code>categories</code> <a class="header-anchor" href="#_13-3-categories" aria-label="Permalink to &quot;13.3 `categories`&quot;">тАЛ</a></h2><p>Stores reporting categories.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>name</code></li><li><code>parent_category_id</code></li><li><code>category_type</code></li><li><code>tax_relevant</code></li><li><code>business_relevant</code></li><li><code>household_relevant</code></li><li><code>legal_relevant</code></li><li><code>is_active</code></li><li><code>notes</code></li></ul><p>Category types:</p><ul><li>income</li><li>expense</li><li>transfer</li><li>liability</li><li>asset</li><li>adjustment</li></ul><hr><h2 id="_13-4-vendors" tabindex="-1">13.4 <code>vendors</code> <a class="header-anchor" href="#_13-4-vendors" aria-label="Permalink to &quot;13.4 `vendors`&quot;">тАЛ</a></h2><p>Normalized payees.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>name</code></li><li><code>default_category_id</code></li><li><code>default_entity_id</code></li><li><code>default_context_id</code></li><li><code>notes</code></li><li><code>created_at</code></li><li><code>updated_at</code></li></ul><hr><h2 id="_13-5-contexts" tabindex="-1">13.5 <code>contexts</code> <a class="header-anchor" href="#_13-5-contexts" aria-label="Permalink to &quot;13.5 `contexts`&quot;">тАЛ</a></h2><p>Projects, purposes, or operational buckets.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>name</code></li><li><code>context_type</code></li><li><code>description</code></li><li><code>is_active</code></li><li><code>created_at</code></li><li><code>updated_at</code></li></ul><p>Context examples:</p><ul><li>household</li><li>personal</li><li>business</li><li>legal</li><li>caregiver</li><li>tax</li><li>vehicle</li><li>medical</li><li>emergency</li></ul><hr><h2 id="_13-6-statements" tabindex="-1">13.6 <code>statements</code> <a class="header-anchor" href="#_13-6-statements" aria-label="Permalink to &quot;13.6 `statements`&quot;">тАЛ</a></h2><p>Represents imported bank/card statements.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>account_id</code></li><li><code>statement_start_date</code></li><li><code>statement_end_date</code></li><li><code>statement_date</code></li><li><code>beginning_balance</code></li><li><code>ending_balance</code></li><li><code>source_file_name</code></li><li><code>source_file_url</code></li><li><code>import_status</code></li><li><code>notes</code></li><li><code>created_at</code></li></ul><hr><h2 id="_13-7-import-batches" tabindex="-1">13.7 <code>import_batches</code> <a class="header-anchor" href="#_13-7-import-batches" aria-label="Permalink to &quot;13.7 `import_batches`&quot;">тАЛ</a></h2><p>Tracks each import event.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>account_id</code></li><li><code>statement_id</code></li><li><code>source_type</code></li><li><code>source_file_name</code></li><li><code>imported_at</code></li><li><code>row_count</code></li><li><code>duplicate_count</code></li><li><code>status</code></li><li><code>notes</code></li></ul><p>Source types:</p><ul><li>csv</li><li>manual</li><li>pdf</li><li>api</li><li>migration</li></ul><hr><h2 id="_13-8-raw-transactions" tabindex="-1">13.8 <code>raw_transactions</code> <a class="header-anchor" href="#_13-8-raw-transactions" aria-label="Permalink to &quot;13.8 `raw_transactions`&quot;">тАЛ</a></h2><p>Stores untouched imported transaction data.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>import_batch_id</code></li><li><code>statement_id</code></li><li><code>account_id</code></li><li><code>raw_date</code></li><li><code>raw_posted_date</code></li><li><code>raw_description</code></li><li><code>raw_amount</code></li><li><code>raw_balance</code></li><li><code>raw_category</code></li><li><code>raw_reference</code></li><li><code>source_row_hash</code></li><li><code>matched_transaction_id</code></li><li><code>created_at</code></li></ul><p>This table preserves source truth.</p><hr><h2 id="_13-9-ledger-transactions" tabindex="-1">13.9 <code>ledger_transactions</code> <a class="header-anchor" href="#_13-9-ledger-transactions" aria-label="Permalink to &quot;13.9 `ledger_transactions`&quot;">тАЛ</a></h2><p>The normalized unified ledger.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>transaction_date</code></li><li><code>posted_date</code></li><li><code>account_id</code></li><li><code>vendor_id</code></li><li><code>payee_text</code></li><li><code>description</code></li><li><code>amount</code></li><li><code>direction</code></li><li><code>category_id</code></li><li><code>entity_id</code></li><li><code>context_id</code></li><li><code>source_raw_transaction_id</code></li><li><code>source_statement_id</code></li><li><code>transfer_group_id</code></li><li><code>review_status</code></li><li><code>confidence_score</code></li><li><code>tax_relevant</code></li><li><code>business_relevant</code></li><li><code>household_relevant</code></li><li><code>legal_relevant</code></li><li><code>receipt_url</code></li><li><code>notes</code></li><li><code>created_at</code></li><li><code>updated_at</code></li></ul><p>Direction values:</p><ul><li>income</li><li>expense</li><li>transfer_in</li><li>transfer_out</li><li>adjustment</li></ul><p>Review statuses:</p><ul><li>inbox</li><li>reviewed</li><li>needs_info</li><li>ignored</li><li>duplicate</li></ul><hr><h2 id="_13-10-transaction-splits" tabindex="-1">13.10 <code>transaction_splits</code> <a class="header-anchor" href="#_13-10-transaction-splits" aria-label="Permalink to &quot;13.10 `transaction_splits`&quot;">тАЛ</a></h2><p>Allows one transaction to be split across multiple categories/entities/contexts.</p><p>Example:</p><p>A $60 Walmart purchase:</p><ul><li>$30 groceries</li><li>$15 medical supplies</li><li>$15 household supplies</li></ul><p>Important fields:</p><ul><li><code>id</code></li><li><code>ledger_transaction_id</code></li><li><code>amount</code></li><li><code>category_id</code></li><li><code>entity_id</code></li><li><code>context_id</code></li><li><code>notes</code></li></ul><hr><h2 id="_13-11-rules" tabindex="-1">13.11 <code>rules</code> <a class="header-anchor" href="#_13-11-rules" aria-label="Permalink to &quot;13.11 `rules`&quot;">тАЛ</a></h2><p>Auto-categorization rules.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>rule_name</code></li><li><code>match_field</code></li><li><code>match_operator</code></li><li><code>match_value</code></li><li><code>account_id</code></li><li><code>vendor_id</code></li><li><code>category_id</code></li><li><code>entity_id</code></li><li><code>context_id</code></li><li><code>direction</code></li><li><code>confidence_score</code></li><li><code>is_active</code></li><li><code>created_at</code></li></ul><p>Example:</p><p>If description contains <code>ASTOUND</code>, set:</p><ul><li>vendor = Astound</li><li>category = Internet</li><li>entity = Household</li><li>context = Household Operations</li></ul><hr><h2 id="_13-12-reconciliation-runs" tabindex="-1">13.12 <code>reconciliation_runs</code> <a class="header-anchor" href="#_13-12-reconciliation-runs" aria-label="Permalink to &quot;13.12 `reconciliation_runs`&quot;">тАЛ</a></h2><p>Tracks statement reconciliation.</p><p>Important fields:</p><ul><li><code>id</code></li><li><code>account_id</code></li><li><code>statement_id</code></li><li><code>period_start</code></li><li><code>period_end</code></li><li><code>expected_start_balance</code></li><li><code>expected_end_balance</code></li><li><code>calculated_end_balance</code></li><li><code>difference</code></li><li><code>status</code></li><li><code>notes</code></li><li><code>created_at</code></li></ul><hr><h1 id="_14-key-views" tabindex="-1">14. Key Views <a class="header-anchor" href="#_14-key-views" aria-label="Permalink to &quot;14. Key Views&quot;">тАЛ</a></h1><p>Database views should power reports.</p><h2 id="v-unreviewed-transactions" tabindex="-1"><code>v_unreviewed_transactions</code> <a class="header-anchor" href="#v-unreviewed-transactions" aria-label="Permalink to &quot;`v_unreviewed_transactions`&quot;">тАЛ</a></h2><p>Shows all transactions needing review.</p><h2 id="v-unified-ledger" tabindex="-1"><code>v_unified_ledger</code> <a class="header-anchor" href="#v-unified-ledger" aria-label="Permalink to &quot;`v_unified_ledger`&quot;">тАЛ</a></h2><p>Clean ledger with joined names:</p><ul><li>account name</li><li>vendor name</li><li>category name</li><li>entity name</li><li>context name</li></ul><h2 id="v-cashflow-monthly" tabindex="-1"><code>v_cashflow_monthly</code> <a class="header-anchor" href="#v-cashflow-monthly" aria-label="Permalink to &quot;`v_cashflow_monthly`&quot;">тАЛ</a></h2><p>Monthly income, expenses, and net.</p><h2 id="v-spending-by-category" tabindex="-1"><code>v_spending_by_category</code> <a class="header-anchor" href="#v-spending-by-category" aria-label="Permalink to &quot;`v_spending_by_category`&quot;">тАЛ</a></h2><p>Category totals by date range.</p><h2 id="v-spending-by-entity" tabindex="-1"><code>v_spending_by_entity</code> <a class="header-anchor" href="#v-spending-by-entity" aria-label="Permalink to &quot;`v_spending_by_entity`&quot;">тАЛ</a></h2><p>Totals by person/entity.</p><h2 id="v-spending-by-context" tabindex="-1"><code>v_spending_by_context</code> <a class="header-anchor" href="#v-spending-by-context" aria-label="Permalink to &quot;`v_spending_by_context`&quot;">тАЛ</a></h2><p>Totals by project/context.</p><h2 id="v-legal-expenses" tabindex="-1"><code>v_legal_expenses</code> <a class="header-anchor" href="#v-legal-expenses" aria-label="Permalink to &quot;`v_legal_expenses`&quot;">тАЛ</a></h2><p>All legal-relevant transactions.</p><h2 id="v-household-expenses" tabindex="-1"><code>v_household_expenses</code> <a class="header-anchor" href="#v-household-expenses" aria-label="Permalink to &quot;`v_household_expenses`&quot;">тАЛ</a></h2><p>All household-relevant transactions.</p><h2 id="v-business-expenses" tabindex="-1"><code>v_business_expenses</code> <a class="header-anchor" href="#v-business-expenses" aria-label="Permalink to &quot;`v_business_expenses`&quot;">тАЛ</a></h2><p>All business-relevant transactions.</p><h2 id="v-possible-duplicates" tabindex="-1"><code>v_possible_duplicates</code> <a class="header-anchor" href="#v-possible-duplicates" aria-label="Permalink to &quot;`v_possible_duplicates`&quot;">тАЛ</a></h2><p>Potential duplicate imports.</p><h2 id="v-transfers" tabindex="-1"><code>v_transfers</code> <a class="header-anchor" href="#v-transfers" aria-label="Permalink to &quot;`v_transfers`&quot;">тАЛ</a></h2><p>Transfer groups and matched internal movement.</p><hr><h1 id="_15-ui-design-principles" tabindex="-1">15. UI Design Principles <a class="header-anchor" href="#_15-ui-design-principles" aria-label="Permalink to &quot;15. UI Design Principles&quot;">тАЛ</a></h1><h2 id="fast-before-fancy" tabindex="-1">Fast before fancy <a class="header-anchor" href="#fast-before-fancy" aria-label="Permalink to &quot;Fast before fancy&quot;">тАЛ</a></h2><p>The app should feel like clearing messages, not doing bookkeeping.</p><h2 id="mobile-first" tabindex="-1">Mobile-first <a class="header-anchor" href="#mobile-first" aria-label="Permalink to &quot;Mobile-first&quot;">тАЛ</a></h2><p>The user may need to enter or review transactions from phone.</p><h2 id="big-tap-targets" tabindex="-1">Big tap targets <a class="header-anchor" href="#big-tap-targets" aria-label="Permalink to &quot;Big tap targets&quot;">тАЛ</a></h2><p>Do not make tiny spreadsheet controls.</p><h2 id="default-to-inbox" tabindex="-1">Default to inbox <a class="header-anchor" href="#default-to-inbox" aria-label="Permalink to &quot;Default to inbox&quot;">тАЛ</a></h2><p>The first screen after login should be:</p><p><strong>Money Inbox</strong></p><h2 id="filters-must-be-obvious" tabindex="-1">Filters must be obvious <a class="header-anchor" href="#filters-must-be-obvious" aria-label="Permalink to &quot;Filters must be obvious&quot;">тАЛ</a></h2><p>Every major ledger view needs quick filters.</p><h2 id="review-should-be-one-click-when-possible" tabindex="-1">Review should be one-click when possible <a class="header-anchor" href="#review-should-be-one-click-when-possible" aria-label="Permalink to &quot;Review should be one-click when possible&quot;">тАЛ</a></h2><p>If the system guesses correctly, user should approve quickly.</p><h2 id="manual-editing-must-be-easy" tabindex="-1">Manual editing must be easy <a class="header-anchor" href="#manual-editing-must-be-easy" aria-label="Permalink to &quot;Manual editing must be easy&quot;">тАЛ</a></h2><p>No hidden modals for every tiny edit.</p><h2 id="keep-visual-clutter-low" tabindex="-1">Keep visual clutter low <a class="header-anchor" href="#keep-visual-clutter-low" aria-label="Permalink to &quot;Keep visual clutter low&quot;">тАЛ</a></h2><p>Use:</p><ul><li>left navigation on desktop</li><li>bottom nav or drawer on mobile</li><li>clean table/list hybrid</li><li>badges for status/context</li><li>persistent search</li><li>quick action buttons</li></ul><hr><h1 id="_16-suggested-navigation" tabindex="-1">16. Suggested Navigation <a class="header-anchor" href="#_16-suggested-navigation" aria-label="Permalink to &quot;16. Suggested Navigation&quot;">тАЛ</a></h1><h2 id="primary-nav" tabindex="-1">Primary nav <a class="header-anchor" href="#primary-nav" aria-label="Permalink to &quot;Primary nav&quot;">тАЛ</a></h2><ul><li>Inbox</li><li>Ledger</li><li>Accounts</li><li>Reports</li><li>Rules</li><li>Imports</li><li>Settings</li></ul><h2 id="secondary-admin-nav" tabindex="-1">Secondary admin nav <a class="header-anchor" href="#secondary-admin-nav" aria-label="Permalink to &quot;Secondary admin nav&quot;">тАЛ</a></h2><ul><li>Categories</li><li>Vendors</li><li>People / Entities</li><li>Contexts</li><li>Reconciliation</li><li>Exports</li></ul><hr><h1 id="_17-mvp-roadmap" tabindex="-1">17. MVP Roadmap <a class="header-anchor" href="#_17-mvp-roadmap" aria-label="Permalink to &quot;17. MVP Roadmap&quot;">тАЛ</a></h1><h2 id="phase-0-тАФ-blueprint-and-schema" tabindex="-1">Phase 0 тАФ Blueprint and schema <a class="header-anchor" href="#phase-0-тАФ-blueprint-and-schema" aria-label="Permalink to &quot;Phase 0 тАФ Blueprint and schema&quot;">тАЛ</a></h2><p>Goal: Define the system before building.</p><p>Tasks:</p><ul><li>finalize table list</li><li>finalize category structure</li><li>finalize context structure</li><li>define account list</li><li>define import CSV requirements</li><li>define review workflow</li><li>create Supabase schema</li></ul><p>Deliverable: Working database schema.</p><hr><h2 id="phase-1-тАФ-core-app-shell" tabindex="-1">Phase 1 тАФ Core app shell <a class="header-anchor" href="#phase-1-тАФ-core-app-shell" aria-label="Permalink to &quot;Phase 1 тАФ Core app shell&quot;">тАЛ</a></h2><p>Goal: Create the web app foundation.</p><p>Tasks:</p><ul><li>create React + TypeScript + Vite app</li><li>connect Supabase</li><li>set up auth</li><li>create layout</li><li>add navigation</li><li>create protected routes</li><li>create basic styling system</li></ul><p>Deliverable: Logged-in app shell with navigation.</p><hr><h2 id="phase-2-тАФ-admin-data-setup" tabindex="-1">Phase 2 тАФ Admin data setup <a class="header-anchor" href="#phase-2-тАФ-admin-data-setup" aria-label="Permalink to &quot;Phase 2 тАФ Admin data setup&quot;">тАЛ</a></h2><p>Goal: Create the supporting tables.</p><p>Screens:</p><ul><li>Accounts</li><li>Categories</li><li>Vendors</li><li>People / Entities</li><li>Contexts</li></ul><p>Tasks:</p><ul><li>list records</li><li>create records</li><li>edit records</li><li>deactivate records</li><li>search/filter records</li></ul><p>Deliverable: Usable admin foundation.</p><hr><h2 id="phase-3-тАФ-manual-transaction-entry" tabindex="-1">Phase 3 тАФ Manual transaction entry <a class="header-anchor" href="#phase-3-тАФ-manual-transaction-entry" aria-label="Permalink to &quot;Phase 3 тАФ Manual transaction entry&quot;">тАЛ</a></h2><p>Goal: Allow quick manual logging.</p><p>Tasks:</p><ul><li>add transaction form</li><li>date/account/vendor/amount/category/entity/context</li><li>notes</li><li>review status</li><li>save to ledger</li></ul><p>Deliverable: Manual ledger works.</p><hr><h2 id="phase-4-тАФ-csv-import" tabindex="-1">Phase 4 тАФ CSV import <a class="header-anchor" href="#phase-4-тАФ-csv-import" aria-label="Permalink to &quot;Phase 4 тАФ CSV import&quot;">тАЛ</a></h2><p>Goal: Import statement transactions.</p><p>Tasks:</p><ul><li>upload CSV</li><li>map columns</li><li>create import batch</li><li>create raw transaction rows</li><li>generate row hashes</li><li>prevent duplicate rows</li><li>display import summary</li></ul><p>Deliverable: CSV statement import works.</p><hr><h2 id="phase-5-тАФ-money-inbox" tabindex="-1">Phase 5 тАФ Money Inbox <a class="header-anchor" href="#phase-5-тАФ-money-inbox" aria-label="Permalink to &quot;Phase 5 тАФ Money Inbox&quot;">тАЛ</a></h2><p>Goal: Create the main workflow.</p><p>Tasks:</p><ul><li>show raw/unreviewed transactions</li><li>suggest vendor/category/context</li><li>quick approve</li><li>edit transaction</li><li>mark duplicate</li><li>mark transfer</li><li>push to reviewed ledger</li></ul><p>Deliverable: User can clean imported transactions.</p><hr><h2 id="phase-6-тАФ-unified-ledger" tabindex="-1">Phase 6 тАФ Unified Ledger <a class="header-anchor" href="#phase-6-тАФ-unified-ledger" aria-label="Permalink to &quot;Phase 6 тАФ Unified Ledger&quot;">тАЛ</a></h2><p>Goal: Create master ledger view.</p><p>Tasks:</p><ul><li>searchable ledger</li><li>filters</li><li>edit transaction</li><li>split transaction</li><li>attach notes</li><li>export CSV</li></ul><p>Deliverable: Central money history works.</p><hr><h2 id="phase-7-тАФ-reports" tabindex="-1">Phase 7 тАФ Reports <a class="header-anchor" href="#phase-7-тАФ-reports" aria-label="Permalink to &quot;Phase 7 тАФ Reports&quot;">тАЛ</a></h2><p>Goal: Turn ledger into useful views.</p><p>Reports:</p><ul><li>cashflow</li><li>by category</li><li>by person/entity</li><li>by context/project</li><li>by account</li><li>household</li><li>business</li><li>legal</li><li>uncategorized</li><li>transfers</li></ul><p>Deliverable: Basic financial intelligence.</p><hr><h2 id="phase-8-тАФ-rules-engine" tabindex="-1">Phase 8 тАФ Rules engine <a class="header-anchor" href="#phase-8-тАФ-rules-engine" aria-label="Permalink to &quot;Phase 8 тАФ Rules engine&quot;">тАЛ</a></h2><p>Goal: Reduce repetitive categorization.</p><p>Tasks:</p><ul><li>create rules table</li><li>apply rules on import</li><li>suggest categories</li><li>let user create rule from transaction</li><li>confidence score</li></ul><p>Deliverable: System starts learning patterns.</p><hr><h2 id="phase-9-тАФ-reconciliation" tabindex="-1">Phase 9 тАФ Reconciliation <a class="header-anchor" href="#phase-9-тАФ-reconciliation" aria-label="Permalink to &quot;Phase 9 тАФ Reconciliation&quot;">тАЛ</a></h2><p>Goal: Verify statements against ledger.</p><p>Tasks:</p><ul><li>compare statement ending balance</li><li>compare ledger-calculated balance</li><li>show differences</li><li>mark reconciled</li></ul><p>Deliverable: Ledger becomes audit-friendly.</p><hr><h2 id="phase-10-тАФ-automation-and-ai" tabindex="-1">Phase 10 тАФ Automation and AI <a class="header-anchor" href="#phase-10-тАФ-automation-and-ai" aria-label="Permalink to &quot;Phase 10 тАФ Automation and AI&quot;">тАЛ</a></h2><p>Goal: Speed up imports and classification.</p><p>Possible features:</p><ul><li>n8n import workflows</li><li>receipt OCR</li><li>AI vendor cleanup</li><li>AI category suggestions</li><li>recurring bill detection</li><li>anomaly detection</li><li>natural language search</li></ul><p>Deliverable: Semi-automated finance assistant.</p><hr><h1 id="_18-initial-category-framework" tabindex="-1">18. Initial Category Framework <a class="header-anchor" href="#_18-initial-category-framework" aria-label="Permalink to &quot;18. Initial Category Framework&quot;">тАЛ</a></h1><h2 id="income" tabindex="-1">Income <a class="header-anchor" href="#income" aria-label="Permalink to &quot;Income&quot;">тАЛ</a></h2><ul><li>Caregiver Income</li><li>Rideshare Income</li><li>Business Income</li><li>Family Contribution</li><li>Refund</li><li>Reimbursement</li><li>Legal Disbursement</li><li>Other Income</li></ul><h2 id="household" tabindex="-1">Household <a class="header-anchor" href="#household" aria-label="Permalink to &quot;Household&quot;">тАЛ</a></h2><ul><li>Rent / Housing</li><li>Utilities</li><li>Internet</li><li>Phone</li><li>Groceries</li><li>Household Supplies</li><li>Repairs</li><li>Furniture</li><li>Appliances</li><li>Shared Subscriptions</li></ul><h2 id="caregiver-medical-support" tabindex="-1">Caregiver / Medical Support <a class="header-anchor" href="#caregiver-medical-support" aria-label="Permalink to &quot;Caregiver / Medical Support&quot;">тАЛ</a></h2><ul><li>Medication</li><li>Medical Supplies</li><li>Transportation</li><li>Food / Special Diet</li><li>Mobility Equipment</li><li>Home Health Support</li></ul><h2 id="transportation" tabindex="-1">Transportation <a class="header-anchor" href="#transportation" aria-label="Permalink to &quot;Transportation&quot;">тАЛ</a></h2><ul><li>Gas</li><li>Vehicle Repair</li><li>Insurance</li><li>Registration</li><li>Rideshare Rental</li><li>Parking</li><li>Tolls</li></ul><h2 id="business" tabindex="-1">Business <a class="header-anchor" href="#business" aria-label="Permalink to &quot;Business&quot;">тАЛ</a></h2><ul><li>Software</li><li>Hosting</li><li>Domain</li><li>Equipment</li><li>Office Supplies</li><li>Client Expense</li><li>Contractor</li><li>Professional Services</li></ul><h2 id="legal" tabindex="-1">Legal <a class="header-anchor" href="#legal" aria-label="Permalink to &quot;Legal&quot;">тАЛ</a></h2><ul><li>Filing Fees</li><li>Copies / Printing</li><li>Postage</li><li>Court Costs</li><li>Legal Research</li><li>Travel for Legal</li><li>Evidence / Records</li></ul><h2 id="personal" tabindex="-1">Personal <a class="header-anchor" href="#personal" aria-label="Permalink to &quot;Personal&quot;">тАЛ</a></h2><ul><li>Food</li><li>Clothing</li><li>Personal Care</li><li>Entertainment</li><li>Subscriptions</li><li>Miscellaneous</li></ul><h2 id="debt-liability" tabindex="-1">Debt / Liability <a class="header-anchor" href="#debt-liability" aria-label="Permalink to &quot;Debt / Liability&quot;">тАЛ</a></h2><ul><li>Loan Payment</li><li>Credit Card Payment</li><li>Cash Advance Repayment</li><li>Overdraft / Fees</li><li>Interest</li></ul><h2 id="transfers" tabindex="-1">Transfers <a class="header-anchor" href="#transfers" aria-label="Permalink to &quot;Transfers&quot;">тАЛ</a></h2><ul><li>Internal Transfer</li><li>Cash Withdrawal</li><li>Cash Deposit</li><li>Account Funding</li><li>Clearing Movement</li></ul><h2 id="adjustments" tabindex="-1">Adjustments <a class="header-anchor" href="#adjustments" aria-label="Permalink to &quot;Adjustments&quot;">тАЛ</a></h2><ul><li>Balance Correction</li><li>Duplicate Correction</li><li>Manual Adjustment</li><li>Unknown</li></ul><hr><h1 id="_19-important-design-decisions" tabindex="-1">19. Important Design Decisions <a class="header-anchor" href="#_19-important-design-decisions" aria-label="Permalink to &quot;19. Important Design Decisions&quot;">тАЛ</a></h1><h2 id="decision-1-one-ledger-many-contexts" tabindex="-1">Decision 1: One ledger, many contexts <a class="header-anchor" href="#decision-1-one-ledger-many-contexts" aria-label="Permalink to &quot;Decision 1: One ledger, many contexts&quot;">тАЛ</a></h2><p>Do not create separate ledgers for each bank.</p><p>Each bank/account is a source.</p><p>The unified ledger is the truth.</p><h2 id="decision-2-raw-data-stays-raw" tabindex="-1">Decision 2: Raw data stays raw <a class="header-anchor" href="#decision-2-raw-data-stays-raw" aria-label="Permalink to &quot;Decision 2: Raw data stays raw&quot;">тАЛ</a></h2><p>Imported rows remain untouched.</p><p>Normalized records link back to raw source rows.</p><h2 id="decision-3-clearing-accounts-are-allowed" tabindex="-1">Decision 3: Clearing accounts are allowed <a class="header-anchor" href="#decision-3-clearing-accounts-are-allowed" aria-label="Permalink to &quot;Decision 3: Clearing accounts are allowed&quot;">тАЛ</a></h2><p>Clearing accounts are important for real life.</p><p>Examples:</p><ul><li>Mom Clearing</li><li>Zai Clearing</li><li>Household Clearing</li><li>Cash Clearing</li><li>Reimbursement Clearing</li></ul><h2 id="decision-4-transfers-need-pairing" tabindex="-1">Decision 4: Transfers need pairing <a class="header-anchor" href="#decision-4-transfers-need-pairing" aria-label="Permalink to &quot;Decision 4: Transfers need pairing&quot;">тАЛ</a></h2><p>Money moving between accounts should not count as income or expense.</p><p>Use <code>transfer_group_id</code>.</p><h2 id="decision-5-reports-should-not-require-duplicate-data" tabindex="-1">Decision 5: Reports should not require duplicate data <a class="header-anchor" href="#decision-5-reports-should-not-require-duplicate-data" aria-label="Permalink to &quot;Decision 5: Reports should not require duplicate data&quot;">тАЛ</a></h2><p>Reports should be generated from ledger views.</p><h2 id="decision-6-manual-entry-matters" tabindex="-1">Decision 6: Manual entry matters <a class="header-anchor" href="#decision-6-manual-entry-matters" aria-label="Permalink to &quot;Decision 6: Manual entry matters&quot;">тАЛ</a></h2><p>Not every transaction will come from a bank statement.</p><p>Cash, informal repayments, and quick notes need manual entry.</p><hr><h1 id="_20-risk-register" tabindex="-1">20. Risk Register <a class="header-anchor" href="#_20-risk-register" aria-label="Permalink to &quot;20. Risk Register&quot;">тАЛ</a></h1><h2 id="risk-overbuilding" tabindex="-1">Risk: Overbuilding <a class="header-anchor" href="#risk-overbuilding" aria-label="Permalink to &quot;Risk: Overbuilding&quot;">тАЛ</a></h2><p>Mitigation: Keep MVP focused on ledger, inbox, import, reports.</p><h2 id="risk-accounting-complexity" tabindex="-1">Risk: Accounting complexity <a class="header-anchor" href="#risk-accounting-complexity" aria-label="Permalink to &quot;Risk: Accounting complexity&quot;">тАЛ</a></h2><p>Mitigation: Do not implement full double-entry in v1.</p><h2 id="risk-dirty-imports" tabindex="-1">Risk: Dirty imports <a class="header-anchor" href="#risk-dirty-imports" aria-label="Permalink to &quot;Risk: Dirty imports&quot;">тАЛ</a></h2><p>Mitigation: Use raw transaction staging and source row hashes.</p><h2 id="risk-duplicate-transactions" tabindex="-1">Risk: Duplicate transactions <a class="header-anchor" href="#risk-duplicate-transactions" aria-label="Permalink to &quot;Risk: Duplicate transactions&quot;">тАЛ</a></h2><p>Mitigation: Use hashes based on account/date/amount/description/reference.</p><h2 id="risk-ui-becomes-spreadsheet-hell" tabindex="-1">Risk: UI becomes spreadsheet hell <a class="header-anchor" href="#risk-ui-becomes-spreadsheet-hell" aria-label="Permalink to &quot;Risk: UI becomes spreadsheet hell&quot;">тАЛ</a></h2><p>Mitigation: Use card/list hybrid for review, not only tables.</p><h2 id="risk-reports-become-inaccurate" tabindex="-1">Risk: Reports become inaccurate <a class="header-anchor" href="#risk-reports-become-inaccurate" aria-label="Permalink to &quot;Risk: Reports become inaccurate&quot;">тАЛ</a></h2><p>Mitigation: Use reviewed status and reconciliation.</p><h2 id="risk-tool-lock-in" tabindex="-1">Risk: Tool lock-in <a class="header-anchor" href="#risk-tool-lock-in" aria-label="Permalink to &quot;Risk: Tool lock-in&quot;">тАЛ</a></h2><p>Mitigation: Use plain Supabase/Postgres schema, not proprietary app-builder logic.</p><hr><h1 id="_21-success-criteria" tabindex="-1">21. Success Criteria <a class="header-anchor" href="#_21-success-criteria" aria-label="Permalink to &quot;21. Success Criteria&quot;">тАЛ</a></h1><p>QiLedger v1 is successful when Cody can:</p><ul><li>import transactions from at least one account</li><li>manually add cash/manual transactions</li><li>categorize transactions quickly</li><li>assign transactions to person/entity/context</li><li>view all money activity in one ledger</li><li>filter by household, business, legal, personal, caregiver</li><li>export transactions for backup or tax/legal use</li><li>identify uncategorized or unreviewed transactions</li><li>produce a basic monthly household report</li><li>produce a basic legal expense report</li><li>produce a basic business expense report</li></ul><hr><h1 id="_22-future-features" tabindex="-1">22. Future Features <a class="header-anchor" href="#_22-future-features" aria-label="Permalink to &quot;22. Future Features&quot;">тАЛ</a></h1><h2 id="ai-assisted-categorization" tabindex="-1">AI-assisted categorization <a class="header-anchor" href="#ai-assisted-categorization" aria-label="Permalink to &quot;AI-assisted categorization&quot;">тАЛ</a></h2><p>Use prior reviewed transactions to suggest:</p><ul><li>vendor</li><li>category</li><li>entity</li><li>context</li><li>tax/legal relevance</li></ul><h2 id="natural-language-queries" tabindex="-1">Natural language queries <a class="header-anchor" href="#natural-language-queries" aria-label="Permalink to &quot;Natural language queries&quot;">тАЛ</a></h2><p>Examples:</p><ul><li>тАЬHow much did we spend on MomтАЩs medical stuff last month?тАЭ</li><li>тАЬShow all legal expenses since January.тАЭ</li><li>тАЬHow much did Zai-related spending cost this week?тАЭ</li><li>тАЬWhat did I spend at Walmart in April?тАЭ</li><li>тАЬShow all transactions over $100 that are unreviewed.тАЭ</li></ul><h2 id="receipt-storage" tabindex="-1">Receipt storage <a class="header-anchor" href="#receipt-storage" aria-label="Permalink to &quot;Receipt storage&quot;">тАЛ</a></h2><p>Attach:</p><ul><li>receipt images</li><li>PDFs</li><li>statement files</li><li>screenshots</li><li>notes</li></ul><h2 id="statement-parser" tabindex="-1">Statement parser <a class="header-anchor" href="#statement-parser" aria-label="Permalink to &quot;Statement parser&quot;">тАЛ</a></h2><p>Support:</p><ul><li>CSV</li><li>PDF</li><li>screenshot/OCR later</li></ul><h2 id="recurring-bill-detection" tabindex="-1">Recurring bill detection <a class="header-anchor" href="#recurring-bill-detection" aria-label="Permalink to &quot;Recurring bill detection&quot;">тАЛ</a></h2><p>Identify recurring bills and expected due dates.</p><h2 id="budget-layer" tabindex="-1">Budget layer <a class="header-anchor" href="#budget-layer" aria-label="Permalink to &quot;Budget layer&quot;">тАЛ</a></h2><p>Add budget planning after ledger is stable.</p><h2 id="forecasting" tabindex="-1">Forecasting <a class="header-anchor" href="#forecasting" aria-label="Permalink to &quot;Forecasting&quot;">тАЛ</a></h2><p>Predict upcoming cash needs based on:</p><ul><li>recurring bills</li><li>average spending</li><li>scheduled payments</li><li>expected income</li></ul><h2 id="formal-accounting-mode" tabindex="-1">Formal accounting mode <a class="header-anchor" href="#formal-accounting-mode" aria-label="Permalink to &quot;Formal accounting mode&quot;">тАЛ</a></h2><p>Later optional layer:</p><ul><li>double-entry journal entries</li><li>chart of accounts</li><li>balance sheet</li><li>profit and loss</li><li>equity/liability tracking</li></ul><p>Not v1.</p><hr><h1 id="_23-build-instruction-for-gemini-codex" tabindex="-1">23. Build Instruction for Gemini / Codex <a class="header-anchor" href="#_23-build-instruction-for-gemini-codex" aria-label="Permalink to &quot;23. Build Instruction for Gemini / Codex&quot;">тАЛ</a></h1><p>Use this as the project direction:</p><p>Build a mobile-first React + TypeScript + Vite web app connected to Supabase. The app is a custom financial ledger system called QiLedger. It should use Supabase Postgres as the source of truth and provide a fast user interface for importing, reviewing, categorizing, and reporting money activity across personal, household, business, legal, and caregiver contexts.</p><p>The first version should not attempt to recreate QuickBooks. It should focus on:</p><ul><li>accounts</li><li>entities</li><li>categories</li><li>vendors</li><li>contexts</li><li>manual transaction entry</li><li>CSV import</li><li>raw transaction staging</li><li>review inbox</li><li>unified ledger</li><li>basic reports</li><li>CSV export</li></ul><p>Design the UI for fast review and filtering. The default landing screen after login should be the Money Inbox. Use clean navigation, mobile-first layout, and minimal cognitive clutter.</p><p>The database should preserve raw imported transaction data separately from normalized ledger transactions. All reports should come from the normalized unified ledger and database views.</p><hr><h1 id="_24-mvp-build-order" tabindex="-1">24. MVP Build Order <a class="header-anchor" href="#_24-mvp-build-order" aria-label="Permalink to &quot;24. MVP Build Order&quot;">тАЛ</a></h1><p>Build in this exact order:</p><ol><li>Supabase schema</li><li>Auth and app shell</li><li>Accounts/categories/entities/contexts admin screens</li><li>Manual transaction entry</li><li>Unified ledger view</li><li>CSV import into raw transactions</li><li>Money Inbox review workflow</li><li>Basic reports</li><li>Rules engine</li><li>Reconciliation</li></ol><p>Do not build dashboards first.</p><p>Dashboards come after transaction data is clean.</p><hr><h1 id="_25-bottom-line-strategy" tabindex="-1">25. Bottom-Line Strategy <a class="header-anchor" href="#_25-bottom-line-strategy" aria-label="Permalink to &quot;25. Bottom-Line Strategy&quot;">тАЛ</a></h1><p>The win is not тАЬhaving another finance app.тАЭ</p><p>The win is having a <strong>money command center</strong> that reflects real life:</p><ul><li>household chaos</li><li>caregiver expenses</li><li>personal survival money</li><li>business operations</li><li>legal documentation</li><li>reimbursements</li><li>shared responsibilities</li><li>tax support</li><li>messy bank data</li></ul><p>QiLedger should make the money story visible.</p><p>Not perfect. Visible.</p><p>Then visible becomes manageable. Manageable becomes reportable. Reportable becomes leverage.</p>',489)])])}const m=i(o,[["render",r]]);export{p as __pageData,m as default};
